// Prepare CAPI Data: Split profiles if passed as array
const items = $input.all();
const results = [];

for (const item of items) {
  const data = item.json.orderData || item.json;
  const profiles = data['metaPixelProfiles'] || [];

  if (profiles.length === 0 && data['pixelId']) {
      // Backward compat: single profile
      profiles.push({ pixelId: data['pixelId'], capiToken: data['capiToken'], testCode: data['testCode'] });
  }

  for (const profile of profiles) {
    results.push({
      json: {
        ...data,
        ...profile
      }
    });
  }
}

return results;

const crypto = require('crypto');

const item = $input.item.json;

// Helper to hash
function sha256(val) {
  if (!val) return undefined;
  return crypto.createHash('sha256').update(val).digest('hex');
}

// Normalize Phone (Algeria specific logic included)
let phone = item.phone ? item.phone.toString().replace(/\D/g, '') : '';
if (phone.startsWith('05') || phone.startsWith('06') || phone.startsWith('07')) {
  phone = '213' + phone.substring(1);
}
if (phone.startsWith('5') || phone.startsWith('6') || phone.startsWith('7')) {
  // Assume missing 0
  phone = '213' + phone;
}

// Split Name
const nameParts = item.name ? item.name.trim().split(/\s+/) : [];
const fn = nameParts.length > 0 ? nameParts[0].toLowerCase() : undefined;
const ln = nameParts.length > 1 ? nameParts.slice(1).join(' ').toLowerCase() : undefined;

// Email (normalize and hash)
const em = item.email ? sha256(item.email.trim().toLowerCase()) : undefined;

// Location (City/State/Country)
const ct = item.commune ? sha256(item.commune.trim().toLowerCase()) : undefined;
const st = item.wilaya ? sha256(item.wilaya.trim().toLowerCase()) : undefined;
const country = sha256('dz');

// Construct User Data
const user_data = {
  em,
  ph: phone ? sha256(phone) : undefined,
  fn: fn ? sha256(fn) : undefined,
  ln: ln ? sha256(ln) : undefined,
  ct,
  st,
  country,
  fbp: item.fbp,
  fbc: item.fbc,
  client_ip_address: item.clientIp,
  client_user_agent: item.userAgent || item.client_user_agent
};

return {
  pixelId: item.pixelId,
  capiToken: item.capiToken,
  testCode: item.testCode,
  event_name: item.status === 'abandoned' ? 'InitiateCheckout' : 'Purchase',
  event_time: Math.floor(Date.now() / 1000),
  event_id: item.event_id,
  event_source_url: item.shopDomain,
  action_source: 'website',
  user_data,
  custom_data: {
    value: item.totalPrice,
    currency: 'DZD',
    content_ids: [item.productId],
    content_type: 'product',
    content_name: item.productTitle,
    num_items: item.quantity
  }
};
